import type { ResponseConfig, RouteParameter, ZodContentObject, ZodRequestBody } from '@asteasolutions/zod-to-openapi/dist/openapi-registry';
import type { ZodType } from 'zod';
export type RawRouterHandlerFunction<TParams = Record<string, string>> = (params: TParams, path: string) => Promise<Response | undefined>;
export type RouterHandlerFunction<TBody = Record<string, any>, TParams = Record<string, string>> = ((body: TBody, params: TParams, path: string) => Promise<Record<string, any> | string | undefined>);
export type RouteFunction<TBody = Record<string, any>, TParams = Record<string, string>> = {
    raw: RawRouterHandlerFunction<TParams>;
} | RouterHandlerFunction<TBody, TParams>;
export type RouteMethod = 'get' | 'post' | 'put' | 'delete' | 'patch' | 'head' | 'options';
export type HttpRoute<TBody = Record<string, any>, TParams = Record<string, string>> = {
    handler: RouteFunction<TBody, TParams>;
    path: string;
    method: RouteMethod;
    zod: () => HttpRouteZod;
};
export type HttpRouteZod = {
    description: string;
    request: {
        body?: ZodRequestBody;
        params?: RouteParameter;
        query?: RouteParameter;
        cookies?: RouteParameter;
        headers?: RouteParameter | ZodType<unknown>[];
    };
    responses: {
        [statusCode: string]: {
            description: string;
            headers?: ResponseConfig['headers'];
            links?: ResponseConfig['links'];
            content?: ZodContentObject;
        };
    };
};
